import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10;

        // Limit the input length to the buffer size
        if (input.length() > bufferSize) {
            input = input.substring(0, bufferSize);
        }

        char[] buffer = new char[bufferSize]; // Buffer of size 10

        // Copy user input into the buffer with proper length checking
        input.getChars(0, Math.min(input.length(), bufferSize), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
